{
  "environment": "development",
  "debug": true,
  "logging": {
    "level": "debug",
    "format": "detailed",
    "output": "console"
  },
  "database": {
    "host": "localhost",
    "port": 5432,
    "name": "myapp_dev",
    "user": "dev_user",
    "password": "dev_password",
    "pool_size": 5,
    "ssl": false
  },
  "api": {
    "port": 3000,
    "host": "localhost",
    "timeout": 30000,
    "rate_limit": 1000
  },
  "cache": {
    "enabled": false,
    "ttl": 300
  },
  "security": {
    "cors_enabled": true,
    "cors_origins": ["http://localhost:3000", "http://localhost:8080"],
    "jwt_secret": "dev-secret-key-not-secure",
    "session_timeout": 3600
  },
  "features": {
    "analytics": false,
    "notifications": false,
    "email_verification": false
  }
}

{
  "environment": "production",
  "debug": false,
  "logging": {
    "level": "error",
    "format": "json",
    "output": "file"
  },
  "database": {
    "host": "prod-db.example.com",
    "port": 5432,
    "name": "myapp_prod",
    "user": "prod_user",
    "password": "${DB_PASSWORD}",
    "pool_size": 50,
    "ssl": true,
    "replica_host": "prod-db-replica.example.com"
  },
  "api": {
    "port": 8080,
    "host": "0.0.0.0",
    "timeout": 60000,
    "rate_limit": 100
  },
  "cache": {
    "enabled": true,
    "ttl": 3600,
    "backend": "redis",
    "redis_host": "prod-redis.example.com",
    "redis_port": 6379
  },
  "security": {
    "cors_enabled": true,
    "cors_origins": ["https://app.example.com", "https://www.example.com"],
    "jwt_secret": "${JWT_SECRET}",
    "session_timeout": 1800,
    "https_only": true,
    "hsts_enabled": true
  },
  "features": {
    "analytics": true,
    "notifications": true,
    "email_verification": true
  },
  "monitoring": {
    "enabled": true,
    "metrics_endpoint": "https://metrics.example.com",
    "health_check_interval": 30000
  }
}
